         };
     }

+    /**
+     * Find cells that are marked as occupied but don't match any window's
+     * recorded allocation. These are "ghost" cells from stale state.
+     */
+    findGhostCells() {
+        const ghosts = [];
+        for (let r = 0; r < this.rows; r++) {
+            for (let c = 0; c < this.cols; c++) {
+                const id = this._cells[r][c];
+                if (id === null) continue;
+                const info = this._windows.get(id);
+                if (!info) {
+                    ghosts.push({col: c, row: r, id, reason: 'no window record'});
+                    continue;
+                }
+                // Check if this cell is within the window's allocation
+                if (c < info.col || c >= info.col + info.spanCols ||
+                    r < info.row || r >= info.row + info.spanRows) {
+                    ghosts.push({col: c, row: r, id, reason: 'outside allocation',
+                        alloc: info});
+                }
+            }
+        }
+        return ghosts;
+    }
+
+    /**
+     * Clear ghost cells — cells marked as occupied that don't match
+     * any window's allocation.
+     */
+    clearGhostCells() {
+        const ghosts = this.findGhostCells();
+        for (const g of ghosts)
+            this._cells[g.row][g.col] = null;
+        return ghosts.length;
+    }
+
     get windowCount() { return this._windows.size; }
     getAllWindows() { return new Map(this._windows); }
 }
